INSERT INTO `events` (`id`, `code`, `title`, `short`, `details`, `date`, `time`, `fee`, `location`, `userfile`, `status`) VALUES
(1, '892101', 'জাতীয় শোক দিবস উপলক্ষে আলোচনা অনুষ্', 'Shor', 'আইডিইবি’র উদ্যোগে জাতির পিতা বঙ্গবন্ধু শেখ মুজিবুর\r\n                                 রহমান এর ৪৭তম শাহাদাৎ বার্ষিকী ও জাতীয় শোক দিবস\r\n                                 উপলক্ষে আলোচনা অনুষ্ঠান আগামি ১২ আগস্ট ২০২২, বিকাল\r\n                                 ৫টায়, আইডিইবি ভবনে অনুষ্ঠিত হবে।', '12/12/2000', '12:10', 500, '', 'event.jpg', 0),
(2, '892101', 'জাতীয় শোক দিবস ', ' Short Description', 'আইডিইবি’র উদ্যোগে জাতির পিতা বঙ্গবন্ধু শেখ মুজিবুর\r\n                                 রহমান এর ৪৭তম শাহাদাৎ বার্ষিকী ও জাতীয় শোক দিবস\r\n                                 উপলক্ষে আলোচনা অনুষ্ঠান আগামি ১২ আগস্ট ২০২২, বিকাল\r\n                                 ৫টায়, আইডিইবি ভবনে অনুষ্ঠিত হবে।', '', '', 0, '', 'event.jpg', 0);
